import Mathlib

structure State where
  x : Int
  y : Int

def transition (s : State) : State :=
  { x := s.x + s.y, y := (-2) * s.y - 1 }

def initialState : State :=
  { x := __VERIFIER_nondet_int(), y := __VERIFIER_nondet_int() }

def loopCondition (s : State) : Bool :=
  s.x ≥ 0

def loop (s : State) : State :=
  if loopCondition s then loop (transition s) else s

def overflow (s : State) : Prop :=
  s.x > Int.maxValue ∨ s.x < Int.minValue

def checkNoOverflow (s : State) : Prop :=
  ¬overflow (loop s)

theorem noOverflowInMain : checkNoOverflow initialState :=
  sorry
```

